sql:
SELECT model
FROM batteries
WHERE battery_id = 1;

SELECT model, capacity
FROM batteries
ORDER BY capacity DESC;

SELECT SUM(quantity_sold) AS total_batteries_sold
FROM sales_data
WHERE transaction_id = 1;

SELECT coverage_details
FROM warranty_information
WHERE start_date = '2023-01-15';

SELECT model
FROM batteries
ORDER BY model;

SELECT COUNT(review_id) AS total_reviews
FROM battery_reviews
WHERE battery_id = 1;
